// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getAllRiders as getUsers,
  getCaptains as getApprovedCaptains,
  getPendingCaptains,
  getAllRides as getRides,
  approveRider as approveCaptain,
  rejectRider as rejectCaptain,
} from "../../services/api";
import {
  AppBar,
  Toolbar,
  Typography,
  Container,
  Paper,
  Tabs,
  Tab,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
} from "@mui/material";

export default function AdminDashboard() {
  const [tab, setTab] = useState("overview");
  const [overview, setOverview] = useState({});
  const [users, setUsers] = useState([]);
  const [captains, setCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [openDocsModal, setOpenDocsModal] = useState(false);
  const [selectedDocuments, setSelectedDocuments] = useState({});
  const [selectedRider, setSelectedRider] = useState(null);

  useEffect(() => {
    fetchData();
  }, [tab]);

  const fetchData = async () => {
    try {
      if (tab === "overview") {
        const res = await getOverview();
        setOverview(res.data);
      } else if (tab === "users") {
        const res = await getUsers();
        setUsers(res.data);
      } else if (tab === "captains") {
        const res = await getApprovedCaptains();
        setCaptains(res.data);
      } else if (tab === "pending") {
        const res = await getPendingCaptains();
        setPendingCaptains(res.data);
      } else if (tab === "rides") {
        const res = await getRides();
        setRides(res.data);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handleTabChange = (event, newValue) => {
    setTab(newValue);
  };

  const handleApprove = async (id) => {
    await approveCaptain(id);
    fetchData();
  };

  const handleReject = async (id) => {
    await rejectCaptain(id);
    fetchData();
  };

  const handleViewDocuments = (item) => {
    setSelectedDocuments(item.documents || {});
    setSelectedRider(item || null);
    setOpenDocsModal(true);
  };

  const renderDocumentsCell = (item) => {
    if (!item.documents || Object.keys(item.documents).length === 0) return "-";
    return (
      <Button
        variant="outlined"
        size="small"
        onClick={() => handleViewDocuments(item)}
      >
        View Documents
      </Button>
    );
  };

  return (
    <Container>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6">Admin Dashboard</Typography>
        </Toolbar>
      </AppBar>
      <Paper style={{ marginTop: 20, padding: 20 }}>
        <Tabs value={tab} onChange={handleTabChange}>
          <Tab label="Overview" value="overview" />
          <Tab label="Users" value="users" />
          <Tab label="Captains" value="captains" />
          <Tab label="Pending" value="pending" />
          <Tab label="Rides" value="rides" />
        </Tabs>

        {/* Pending Captains */}
        {tab === "pending" && (
          <TableContainer component={Paper} style={{ marginTop: 20 }}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Name</TableCell>
                  <TableCell>Email</TableCell>
                  <TableCell>Mobile</TableCell>
                  <TableCell>Role</TableCell>
                  <TableCell>Documents</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {pendingCaptains.map((item) => (
                  <TableRow key={item._id}>
                    <TableCell>{item.fullName}</TableCell>
                    <TableCell>{item.email}</TableCell>
                    <TableCell>{item.mobile}</TableCell>
                    <TableCell>{item.role}</TableCell>
                    <TableCell>{renderDocumentsCell(item)}</TableCell>
                    <TableCell>
                      <Button
                        variant="contained"
                        color="success"
                        size="small"
                        onClick={() => handleApprove(item._id)}
                        style={{ marginRight: 10 }}
                      >
                        Approve
                      </Button>
                      <Button
                        variant="contained"
                        color="error"
                        size="small"
                        onClick={() => handleReject(item._id)}
                      >
                        Reject
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}

        {/* Documents Modal */}
        <Dialog
          open={openDocsModal}
          onClose={() => setOpenDocsModal(false)}
          maxWidth="md"
          fullWidth
        >
          <DialogTitle>Rider Details & Documents</DialogTitle>
          <DialogContent>
            {selectedRider && (
              <>
                <Typography variant="subtitle1">
                  <strong>Name:</strong> {selectedRider.fullName}
                </Typography>
                <Typography variant="subtitle1">
                  <strong>Email:</strong> {selectedRider.email}
                </Typography>
                <Typography variant="subtitle1">
                  <strong>Mobile:</strong> {selectedRider.mobile}
                </Typography>
                <Typography variant="subtitle1">
                  <strong>Role:</strong> {selectedRider.role}
                </Typography>
                <hr />
              </>
            )}

            {selectedDocuments && Object.keys(selectedDocuments).length > 0 ? (
              Object.entries(selectedDocuments).map(([key, url]) => (
                <div key={key} style={{ marginBottom: "10px" }}>
                  <Typography variant="body2">{key}</Typography>
                  <a href={url} target="_blank" rel="noopener noreferrer">
                    Open Document
                  </a>
                </div>
              ))
            ) : (
              <Typography>No documents uploaded.</Typography>
            )}
          </DialogContent>
        </Dialog>
      </Paper>
    </Container>
  );
}
